var e=[{id:`L3_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`이상하네……. 공장 안에 아무도 없어. `,JPN:`おかしいわ……工場の中に誰もいない。`,ENG:`Odd... The factory seems empty.`,TWN:`奇怪……工廠裡怎麼都沒人？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`전원도 내려가 있고……. 설마?`,JPN:`電源も入っていないし……まさか？`,ENG:`Even the power’s out... Could it be?!`,TWN:`而且電源也都沒有開啟……難道？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`CRIMINAL_NPC_ALPHA_QM`,text:{KOREA:`웰컴입니다. 이노베이션 대표.`,JPN:`ウェルカムです。イノベーション代表。`,ENG:`Welcome, CEO of Innovation.`,TWN:`歡迎光臨，改革代表。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`ELECTRONICSCEO_NPC_ALPHA_NULL`,text:{KOREA:`……아니, 괴물 아가씨라고 불러드려야 할까요?`,JPN:`……いや、化け物のお嬢様と呼ぶべきでしょうか？`,ENG:`Or should I say, Ms. Monster?`,TWN:`……不，還是我應該稱呼你為怪物小姐？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`일렉트로닉스 대표님! 무사하셨군요!`,JPN:`エレクトロニクス代表！　ご無事だったのですね！`,ENG:`Oh, thank goodness! You’re alive!`,TWN:`電子代表！你沒事就好！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`ELECTRONICSCEO_NPC_ALPHA_NULL`,text:{KOREA:`정말 범인이 나타날지 반신반의했는데…….`,JPN:`本当に犯人が現れるか半信半疑でしたが……`,ENG:`I was half in disbelief whether you’d come or not...`,TWN:`我原本還半信半疑地想說犯人真的會出現嗎……`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`ELECTRONICSCEO_NPC_ALPHA_NULL`,text:{KOREA:`습격에 대비하라던 이 실장 말이 정확했어요.`,JPN:`襲撃に備えろと言っていたシノザキ室長の言うとおりでした。`,ENG:`Guess Chief Lee was right to prepare for an ambush.`,TWN:`李室長說的果然沒錯，幸好我有準備！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`네? 이진 언니가 대표님께 그런 말을 했다고요?`,JPN:`はい？　ホノカさんが代表にそんなことを言ったのですか？`,ENG:`Huh? Jin told you to do so?`,TWN:`嗯？李珍姐已經有通知過代表嗎？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`그렇구나……. 저는 그런 줄도 모르고…….`,JPN:`そうだったのね……私はそんなことも知らずに……`,ENG:`I see... I didn’t know...`,TWN:`原來如此……我都不知道……`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`ELECTRONICSCEO_NPC_ALPHA_NULL`,text:{KOREA:`그래요. 알고 있었다면 여기 오지도 않았겠죠.`,JPN:`そうです。知っていたらここには来もしなかったでしょう。`,ENG:`Yes. If you knew, you wouldn’t have come.`,TWN:`那當然，要是被你知道的話，你還會來嗎？！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L38_1`,type:`dialog`,speaker:`ELECTRONICSCEO_NPC_ALPHA_NULL`,text:{KOREA:`네 범행은 여기서 끝이다, 이 괴물아.`,JPN:`お前の犯行はここで終わりだ、この化け物め。`,ENG:`Your terror ends here, you monster.`,TWN:`你的罪行就到此為止，怪物！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L39_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`범행……?`,JPN:`犯行……？`,ENG:`Terror...?`,TWN:`罪行……？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L40_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`아, 그렇구나! 제가 아직 설명을 안 드렸네요!`,JPN:`あ、そうでしたね！　まだ説明しておりませんでした！`,ENG:`Ah, I see! I haven’t explained it to you yet!`,TWN:`喔～原來是這樣！都忘記跟你說明！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};